  const params = new URLSearchParams(location.search);
  const state = params.get('state') || 'ready';
  const mode = params.get('mode') || 'marathon';
  const app = document.querySelector('.app');
  const validStates = ['ready', 'playing', 'paused', 'modes', 'puzzle-select', 'puzzle-playing', 'puzzle-complete', 'puzzle-fail'];
  const validModes = ['marathon', 'race', 'puzzle'];
  app.dataset.state = validStates.includes(state) ? state : 'ready';
  app.dataset.mode = validModes.includes(mode) ? mode : 'marathon';
  const names = {marathon: '马拉松模式', race: '竞速模式', puzzle: '解谜模式'};
  document.querySelector('.session-mode').textContent = names[app.dataset.mode];
  const rules = {
    marathon: '目标：累积得分　结束：堆叠到顶',
    race: '目标：完成 20 行　结束：完成目标',
    puzzle: '目标：清空棋盘　结束：方块用尽',
  };
  document.querySelectorAll('.mode-choice').forEach((choice) => {
    choice.classList.toggle('selected', choice.textContent.trim() === names[app.dataset.mode]);
  });
  document.querySelectorAll('.selected-summary').forEach((summary) => {
    summary.innerHTML = `<b>${names[app.dataset.mode]}</b><span>${rules[app.dataset.mode]}</span>`;
  });
  if (params.get('stress') === 'puzzle-long') {
    document.querySelector('.puzzle-stats div:nth-child(1) dd').textContent = '3/6　示例：玄武裂隙 · 困难';
    document.querySelector('.puzzle-stats div:nth-child(2) dd').textContent = '12 块';
    document.querySelector('.puzzle-stats div:nth-child(3) dd').textContent = '12';
    document.querySelector('.puzzle-stats div:nth-child(4) dd').textContent = '清空棋盘';
  }

